parts = meta_content.split('!')
print("Number of parts:", len(parts))

def db(s):
    return s.replace('#', 'W')

def safe_b64decode(s):
    # Fix padding
    s = db(s)
    missing_padding = len(s) % 4
    if missing_padding:
        s += '=' * (4 - missing_padding)
    try:
        return base64.b64decode(s).decode('utf-8')
    except Exception as e:
        return f"ERROR: {e} for string {s}"

for i, part in enumerate(parts):
    print(f"\n--- Part {i} ---")
    if part.startswith("Imh0dHBz"):
        print("URL Part Decoded:", safe_b64decode(part))
    else:
        decoded = safe_b64decode(part)
        print("Decoded:")
        print(decoded)
